import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { jwtDecode } from 'jwt-decode';

function Login({ setToken }) {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const response = await axios.post('http://192.168.66.59:5000/api/auth/login', { email, password });
            const token = response.data.token;
            setToken(token);
            const decoded = jwtDecode(token);
            if (decoded.is_admin) {
                navigate('/admin'); 
            } else {
                navigate('/countries'); 
            }
        } catch (err) {
            setError('Неправильный пароль или почта!');
        }
    };

    const navigateToRegister = () => {
        navigate('/register');
    };
    const navigateToLogin = () => {
        navigate('/login');
    };
    return (
        <div>
            <h1>Вход в учетную запись</h1>
            <form onSubmit={handleSubmit}>
                <input type="email" placeholder="Почта" value={email} onChange={(e) => setEmail(e.target.value)} />
                <input type="password" placeholder="Пароль" value={password} onChange={(e) => setPassword(e.target.value)} />
                <button type="submit">Вход</button>
            </form>
            {error && <p>{error}</p>}
            <p>
              <button onClick={navigateToRegister}>Зарегистрироваться</button>
            </p>
        </div>
    );
}

export default Login;
